/**
 * @ch Feature Wheel 純邏輯層
 * 不依賴 cc 框架型別，可獨立單元測試（對應 P1 設計分層：功能層）
 * 內容：segment 資料模型、server 介面 adapter、角度計算、type→icon 對照
 */

/**
 * @ch 轉輪格子功能類型
 * ⚠️ 數值「刻意對齊後端 server enum」：None=-1, FreeGame=0, Multiplier=1, Upgrade=2, Transfer(符號轉換)=3, Grand(GrandJP)=4
 * 目前 server↔client 同號 → ParseServerWheelData 直接 passthrough（不做映射）。
 * 若後端日後改號，務必改回「保留本地編號 + 在 ParseServerWheelData 內加映射層」，不可讓兩邊默默錯位。
 * 數值契約由測試「enum 對齊 server」鎖定，誤改 enum 值會讓測試變紅。
 */
export enum FeatureWheelSegmentType {
    /**@ch 未觸發（空格，不顯示 icon）*/
    None = -1,
    /**@ch 觸發 Free Game（MG 專用；server: FreeGame）*/
    FreeGame = 0,
    /**@ch 乘倍（server: Multiplier）*/
    Multiplier = 1,
    /**@ch 升級（server: Upgrade）*/
    Upgrade = 2,
    /**@ch 符號轉換（server: Transfer）*/
    SymbolConvert = 3,
    /**@ch GRAND JP（FG 專用；server: Grand）*/
    GrandJP = 4,
}

/** @ch 單格描述子 */
export interface SegmentDescriptor {
    type: FeatureWheelSegmentType;
}

/** @ch 落點結果（PLAY_SPIN callback 回傳） */
export interface SpinResult {
    index: number;
    type: FeatureWheelSegmentType;
}

/** @ch 轉輪格數（固定 12 格） */
export const FEATURE_WHEEL_SEGMENT_COUNT = 12;

/** @ch 每格角度（12 格均勻 30°） */
export const FEATURE_WHEEL_SEGMENT_ANGLE = 360 / FEATURE_WHEEL_SEGMENT_COUNT;

/**
 * @ch 轉動額外圈數（獎輪手感，單一值 · DR-14）
 * 注意：值越大峰值角速度越高，12 格重複圖樣易觸發車輪錯覺（視覺反向）。
 * 與 ROTATE_TIME 搭配控制峰值速度，使其遠低於格距一半（15°/frame@60fps）。
 * ⚠️ 由 10 格(36°)改 12 格(30°)後臨界值從 18°→15°/frame 收緊，本次未重調轉速參數。
 */
export const FEATURE_WHEEL_EXTRA_CIRCLES = 2;

/** @ch 未知 type 的預設 icon 索引 */
export const DEFAULT_ICON_INDEX = 0;

/**
 * @ch type → SpriteChange icon 索引對照（前端本地，須與 prefab SpriteFrame 陣列順序對應）
 * ⚠️ DR-12：此對照的「順序語意」與 prefab 圖序須人工核對，dev 斷言只驗數量/key 集合
 */
export const TYPE_ICON_CONFIG: Readonly<Partial<Record<FeatureWheelSegmentType, number>>> = {
    [FeatureWheelSegmentType.FreeGame]: 0,
    [FeatureWheelSegmentType.Multiplier]: 1,
    [FeatureWheelSegmentType.Upgrade]: 2,
    [FeatureWheelSegmentType.SymbolConvert]: 3,
    [FeatureWheelSegmentType.GrandJP]: 4,
    // None 無 icon（不顯示），刻意不列入；TypeToIconIndex 對未列值回預設、BindSegmentIcons 對 None 清空
};

/**
 * @ch type → icon 索引（BC-4）
 * @param type 功能類型
 * @returns SpriteChange 索引；未知 type 回傳預設索引
 */
export function TypeToIconIndex(type: FeatureWheelSegmentType): number {
    const idx = TYPE_ICON_CONFIG[type];
    return idx === undefined ? DEFAULT_ICON_INDEX : idx;
}

/**
 * @ch 判斷 type 是否為已知集合內
 * @param type 功能類型
 */
export function IsKnownSegmentType(type: number): boolean {
    return TYPE_ICON_CONFIG[type as FeatureWheelSegmentType] !== undefined;
}

/**
 * @ch 本輪是否有「有效轉輪」需要演出（純投影，對應 FeatureWheelShowState 進入守衛 / BC-1）
 *
 * 語意：server RoundInfo.WheelFeatures 各項 Type 中，存在任一 ≠ None(-1) → 該輪觸發轉輪、需演出。
 * 全為 None（如 server 給 [-1] / [-1,-1]）或缺值（null/空陣列）→ 無轉輪、不進演出 State。
 *
 * @param types RoundInfo.WheelFeatures.map(w => w.Type)（缺值傳 null/undefined）
 */
export function HasActiveWheel(types: ReadonlyArray<number> | null | undefined): boolean {
    return !!types && types.some(t => t !== FeatureWheelSegmentType.None);
}

/**
 * @ch 本輪是否有「respin 後段」要套用的轉輪效果 → 對應 FeatureResultShowState 進入守衛。
 *
 * 語意：WheelFeatures 各 Type 中存在 Upgrade / Multiplier / SymbolConvert → 末手 respin 後
 * 需先演各自效果再做收分動畫。FreeGame / GrandJP / None 不計入（FG 收分在前段即做）。
 *
 * @param types RoundInfo.WheelFeatures.map(w => w.Type)（缺值傳 null/undefined）
 */
export function HasPostRespinFeature(types: ReadonlyArray<number> | null | undefined): boolean {
    return !!types && types.some(
        t => t === FeatureWheelSegmentType.Upgrade ||
             t === FeatureWheelSegmentType.Multiplier ||
             t === FeatureWheelSegmentType.SymbolConvert,
    );
}

/**
 * @ch 本輪轉輪是否落 FreeGame → 對應 ⑨Scatter 丟場 + ⑩進 FG。
 * 語意：WheelFeatures 各 Type 中存在 FreeGame(0) → 進 FG 前需演 Scatter 丟場（也可能不演）。
 *
 * @param types RoundInfo.WheelFeatures.map(w => w.Type)（缺值傳 null/undefined）
 */
export function HasFreeGameWheel(types: ReadonlyArray<number> | null | undefined): boolean {
    return !!types && types.some(t => t === FeatureWheelSegmentType.FreeGame);
}

/**
 * @ch 預設 12 格 fallback 組成（server 整層無資料時用）
 * 3 符號轉換 + 3 乘倍 + 3 升級 + 1 GRAND JP + 1 Free Game + 1 升級補滿
 */
export function GetDefaultSegments(): SegmentDescriptor[] {
    return [
        { type: FeatureWheelSegmentType.SymbolConvert },
        { type: FeatureWheelSegmentType.Multiplier },
        { type: FeatureWheelSegmentType.Upgrade },
        { type: FeatureWheelSegmentType.SymbolConvert },
        { type: FeatureWheelSegmentType.Multiplier },
        { type: FeatureWheelSegmentType.Upgrade },
        { type: FeatureWheelSegmentType.SymbolConvert },
        { type: FeatureWheelSegmentType.Multiplier },
        { type: FeatureWheelSegmentType.Upgrade },
        { type: FeatureWheelSegmentType.GrandJP },
        { type: FeatureWheelSegmentType.Upgrade },
        { type: FeatureWheelSegmentType.FreeGame },
    ];
}

/** @ch WheelData 第一層索引語意（0:主遊戲 1:免費遊戲） */
export enum WheelDataLayer {
    MainGame = 0,
    FreeGame = 1,
}

/**
 * @ch server 介面隔離 adapter（BC-1 / BC-2）
 * WheelData 結構：IIntAry[]，第一層 = WheelDataLayer（0:MG 1:FG），第二層 Data = 各格的功能類型 int。
 * client enum 目前與 server 同號 → 直接 passthrough（驗證已知值，未知/缺格 → None 不顯示）。
 * 若後端改號，改回此處加映射層即可（呼叫端與型別不變）。
 * 整層無資料（缺層 / Data 非陣列 / Data 為空）→ 回預設 12 格。
 * @param raw server 原始 WheelData（protocol.ar2es2Proto.IIntAry[]；用結構化簽章避免依賴 proto 型別，保住純邏輯層）
 * @param layer 取主遊戲或免費遊戲那一層
 * @returns 剛好 12 格的 SegmentDescriptor 陣列
 */
export function ParseServerWheelData(
    raw: ReadonlyArray<{ Data?: number[] | null }> | null | undefined,
    layer: WheelDataLayer,
): SegmentDescriptor[] {
    const fallback = GetDefaultSegments();

    // 整層無資料 → 全 fallback（BC-2 / 用戶確認：沒有任何資料時用原本預設）
    const layerData = Array.isArray(raw) ? raw[layer]?.Data : null;
    if (!Array.isArray(layerData) || layerData.length === 0) {
        return fallback;
    }

    // 有資料：固定 12 格逐格採用（已知值直接用；未知值 / 缺格 / 非數字 → None 不顯示）
    const result: SegmentDescriptor[] = [];
    for (let i = 0; i < FEATURE_WHEEL_SEGMENT_COUNT; i++) {
        const v = layerData[i];
        const type = (typeof v === 'number' && IsKnownSegmentType(v))
            ? (v as FeatureWheelSegmentType)
            : FeatureWheelSegmentType.None;
        result.push({ type });
    }
    return result;
}

/**
 * @ch 計算單調的絕對目標角（BC-3）
 * 順時針（預設）→ z 角遞減；逆時針 → z 角遞增。兩方向落點 orientation 同為 baseAngle。
 * Cocos +z 為逆時針，故順時針取負向 delta，再疊固定額外圈數，全程不變號（避免視覺反向）。
 * 不沿用 MultiplierManager 的 angleDiff = target - start（會中途反向）。
 * @param landIndex 落點格索引 (0~11)
 * @param currentAngle 輪盤當前角度（度，取自節點 eulerAngles.z）
 * @param clockwise 是否順時針（預設 true）
 * @returns 絕對目標角（度）；clockwise=true 時 < currentAngle，false 時 > currentAngle
 */
export function ComputeTargetAngle(landIndex: number, currentAngle: number, clockwise: boolean = true): number {
    const baseAngle = landIndex * FEATURE_WHEEL_SEGMENT_ANGLE;
    const extra = FEATURE_WHEEL_EXTRA_CIRCLES * 360;
    if (clockwise) {
        // 順時針：z 角遞減。backwardDelta 取正向（0~360）使落點對齊 base，再多轉 extra 整圈
        const backwardDelta = NormalizeAngle(currentAngle - baseAngle);
        return currentAngle - backwardDelta - extra;
    }
    // 逆時針：z 角遞增。forwardDelta 取正向（0~360），等同 NormalizeAngle(baseAngle - currentAngle)
    const forwardDelta = NormalizeAngle(baseAngle - currentAngle);
    return currentAngle + forwardDelta + extra;
}

/**
 * @ch 正規化角度到 0~360（每次轉動結束後呼叫，防 BC-8 連續轉動的累積漂移 · DR-9）
 * @param angle 任意角度（度）
 */
export function NormalizeAngle(angle: number): number {
    return ((angle % 360) + 360) % 360;
}

