import { _decorator, Component, warn, error } from 'cc';
import { eventManager } from 'db://astarte-framework/Managers';
import { BaseSpine } from '../Spine/BaseSpine';

const { ccclass, property } = _decorator;

/**
 * @ch Feature Wheel 宣告動畫事件（獨立命名空間，與 FEATURE_WHEEL_EVENT 不衝突）
 */
export const FEATURE_WHEEL_DECLARE_EVENT = {
    /**
     * @ch 播放宣告動畫：進場 → 退場連續播放
     * @param callback (選填) () => void 進退場全部播完後回調
     */
    PLAY_DECLARE: 'FEATURE_WHEEL_DECLARE_PLAY',
};

/**
 * @ch Feature Wheel 宣告動畫元件
 * 單一職責：收到 PLAY_DECLARE 事件後，播進場動畫，接著播退場動畫（連續一氣呵成）
 * 組合（非繼承）持有一個 BaseSpine 參照來播動畫，沿用其 Promise 化 PlayAnimation；Spine 未指派時優雅降級（warn 不崩）
 */
@ccclass('FeatureWheelDeclare')
export class FeatureWheelDeclare extends Component {
    //#region 屬性
    /**@ch 宣告動畫的 Spine（指派一個帶 BaseSpine 元件的節點）*/
    @property({ type: BaseSpine, displayName: '宣告 Spine' })
    private m_spine: BaseSpine = null;

    /**@ch 進場動畫名稱（Spine 資源到位後在 prefab 填實際 animation 名）*/
    @property({ displayName: '進場動畫名稱' })
    private m_inAnimName: string = 'in';

    /**@ch 退場動畫名稱（Spine 資源到位後在 prefab 填實際 animation 名）*/
    @property({ displayName: '退場動畫名稱' })
    private m_outAnimName: string = 'out';
    //#endregion 屬性

    //#region 變數
    /**@ch 是否播放中（重入守衛：進退場整段期間互斥）*/
    private m_isPlaying = false;
    /**@ch 是否已註冊事件*/
    private m_isEventRegistered = false;

    /**@ch 事件列表*/
    private readonly EVENT_LIST: string[] = [
        FEATURE_WHEEL_DECLARE_EVENT.PLAY_DECLARE,
    ];
    //#endregion 變數

    //#region 生命週期
    onLoad() {
        this.RegisterEvent();
    }

    onDestroy() {
        this.UnregisterEvent();
    }
    //#endregion 生命週期

    //#region 事件註冊
    private RegisterEvent() {
        if (this.m_isEventRegistered) {
            return;
        }
        this.m_isEventRegistered = true;
        this.EVENT_LIST.forEach(event => eventManager.Register(event, this));
    }

    private UnregisterEvent() {
        if (!this.m_isEventRegistered) {
            return;
        }
        this.EVENT_LIST.forEach(event => eventManager.UnRegister(event, this));
        this.m_isEventRegistered = false;
    }

    /**
     * @ch 事件分派
     */
    OnEvent(event: string, ...args: any[]) {
        switch (event) {
            case FEATURE_WHEEL_DECLARE_EVENT.PLAY_DECLARE:
                this.PlayDeclare(typeof args[0] === 'function' ? args[0] : undefined);
                break;
        }
    }
    //#endregion 事件註冊

    //#region 方法
    /**
     * @ch 播放宣告動畫：進場 → 退場連續播放
     * 守衛順序：① 播放中重入 → 忽略
     * 完成訊號鏈：await 進場 → await 退場 → callback → 最後釋放 m_isPlaying
     * @param callback 進退場全部播完後回調
     */
    private async PlayDeclare(callback?: () => void) {
        // ① 重入守衛：播放中忽略本次請求
        if (this.m_isPlaying) {
            warn('FeatureWheelDeclare PlayDeclare 播放中，忽略本次請求');
            return;
        }

        this.m_isPlaying = true;
        // 播放期間顯示節點，整段結束後再隱藏（平時宣告動畫隱藏）
        this.node.active = true;
        try {
            await this.m_spine?.PlayAnimation(this.m_inAnimName);   // 進場（不循環）
            await this.m_spine?.PlayAnimation(this.m_outAnimName);  // 退場（不循環）
            // callback 包獨立 try：呼叫端 callback 自身例外不被遮蔽成「播放失敗」
            try {
                callback?.();
            } catch (cbErr) {
                error('FeatureWheelDeclare PlayDeclare callback 執行失敗: ' + cbErr);
            }
        } catch (e) {
            error('FeatureWheelDeclare PlayDeclare 播放失敗: ' + e);
        } finally {
            this.node.active = false;
            this.m_isPlaying = false;
        }
    }
    //#endregion 方法
}

