307	    /**
308	     * @ch 轉動並落在指定格（IF-3 / BC-3 / BC-6 / BC-7 / BC-8 / BC-9 / EH-1 / EH-3）
309	     * 守衛順序（DR-10）：① 轉動中重入 → ② 未初始化/無資料 → ③ landIndex 範圍
310	     * 完成訊號鏈（DR-2 / BC-7）：await 轉動 → await 落點演出 → callback → 最後釋放 m_isSpinning
311	     * @param landIndex 落點格索引 (0~11)
312	     * @param callback 完成回調，帶選中格 {index, type, value}
313	     */
314	    private async PlaySpin(landIndex: number, callback?: (result: SpinResult) => void) {
315	        // ① BC-9 轉動中重入 → 忽略
316	        if (this.m_isSpinning) {
317	            warn('FeatureWheel PlaySpin 轉動中，忽略本次請求');
318	            return;
319	        }
320	        // ② EH-3 未初始化或無資料
321	        if (!this.m_isInit || this.m_segments.length === 0) {
322	            warn('FeatureWheel PlaySpin 未初始化或尚未設置輪盤資料');
323	            return;
324	        }
325	        // ③ EH-1 landIndex 範圍
326	        if (landIndex < 0 || landIndex >= FEATURE_WHEEL_SEGMENT_COUNT) {
327	            warn(`FeatureWheel PlaySpin landIndex ${landIndex} 超出範圍 0~${FEATURE_WHEEL_SEGMENT_COUNT - 1}`);
328	            return;
329	        }
330	
331	        this.m_isSpinning = true;
332	        // 轉動開始即關閉 Idle：轉完「不」自動恢復；待盤面其他表演結束由 RESUME_IDLE 手動恢復
333	        this.m_isIdle = false;
334	        try {
335	            await this.RotateToIndex(landIndex);     // BC-3 / BC-6
336	            await this.PlayLandAnnounce(landIndex);  // BC-7
337	            const seg = this.m_segments[landIndex];
338	            // callback 包獨立 try（R-1）：呼叫端 callback 自身例外不被遮蔽成「轉動失敗」
339	            try {
340	                callback?.({ index: landIndex, type: seg.type });
341	            } catch (cbErr) {
342	                error('FeatureWheel PlaySpin callback 執行失敗: ' + cbErr);
343	            }
344	        } catch (e) {
345	            error('FeatureWheel PlaySpin 轉動/演出失敗: ' + e);
346	        } finally {
347	            // BC-7：釋放點在 callback 之後，避免演出/回呼期間被重入
348	            this.m_isSpinning = false;
349	        }
350	    }
