352	    /**
353	     * @ch 旋轉到 landIndex，停在頂端指針（BC-3 / BC-6）
354	     * 角度計算用 ComputeTargetAngle（依 m_clockwise 單向單調，不沿用會反向的 angleDiff）
355	     */
356	    private RotateToIndex(landIndex: number): Promise<void> {
357	        return new Promise<void>((resolve) => {
358	            if (!this.m_wheelNode || !this.m_wheelNode.isValid) {
359	                resolve();
360	                return;
361	            }
362	            const currentAngle = this.m_wheelNode.eulerAngles.z;
363	            const targetAngle = ComputeTargetAngle(landIndex, currentAngle, this.m_clockwise);
364	            const anim = { angle: currentAngle };
365	            tween(anim)
366	                .to(FeatureWheelManager.ROTATE_TIME, { angle: targetAngle }, {
367	                    easing: 'cubicOut',
368	                    onUpdate: () => {
369	                        if (this.m_wheelNode?.isValid) {
370	                            this.m_wheelNode.setRotationFromEuler(0, 0, anim.angle);
371	                        }
372	                    },
373	                })
374	                .call(() => {
375	                    // DR-9：轉動結束後正規化角度，防 BC-8 連續轉動累積漂移
376	                    if (this.m_wheelNode?.isValid) {
377	                        this.m_wheelNode.setRotationFromEuler(0, 0, NormalizeAngle(targetAngle));
378	                    }
379	                    resolve();
380	                })
381	                .start();
382	        });
